var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"어...... 제가 카운터라고요?","JPN":"えっ……私がカウンター？","ENG":"Uh... I'm a Counter?","TWN":"呃……你說我是制裁者？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"그래. 어제 관리국에서 공문이 날아왔더구나.","JPN":"そうだ。昨日管理局から公文書が届いてな。","ENG":"Yes. The official document came in from the Administration yesterday.","TWN":"對，昨天管理局寄了份公文。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"네가 어제 사람을 구한 영상을 봤는데 100% 틀림없대.","JPN":"昨日お前が人を救った映像を見たそうで、100％間違いないって言ってるぞ。","ENG":"They are 100% sure after seeing the video of you saving that man yesterday.","TWN":"他們說看了妳昨天救人的影片，100%沒錯。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"워치도 가지고 있잖니?","JPN":"ウォッチも持っているだろう？","ENG":"You even have a Watch.","TWN":"妳不是也有能量環嗎？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"이 시계요?","JPN":"あぁ、この時計ですか？","ENG":"This watch?","TWN":"這個手錶嗎？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"어디서 구했는진 잘 기억이 안 나지만, 저는 그렇게 비싼 건 산 적이 없는데.","JPN":"どこで手に入れたのかは覚えてないけど、こんな高価そうな物……買った記憶ないのに……","ENG":"I'm not sure where I got it, but I've never bought something that expensive.","TWN":"我不記得我是怎麼拿到這隻手錶的，但我從來沒買過很貴的東西欸。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"......원래 워치란 건 자기도 출처를 모르는 경우가 많다고 하더구나.","JPN":"……元々ウォッチというのは、どこで\\n手に入れたのかわからない場合が多いらしい。","ENG":"Counters usually don't realize where their Watches came from.","TWN":"……說到能量環，本來就有很多人不知道自己是怎麼拿到的。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"어쨌든 관리국에서 틀린 말을 할 리는 없을 테니까.","JPN":"とにかく、管理局が間違ったことを言うわけがないからな。","ENG":"Anyway, the Administration has no reason to lie to you.","TWN":"總而言之，管理局是不會認錯的。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"전도유망한 카운터가 된 걸 축하해 줘야겠지? 선생님도 조금은 질투 나는걸?","JPN":"前途有望なカウンターになったことを\\n祝うべきだろう。先生も羨ましいよ。","ENG":"I suppose a celebration is in order for our promising new Counter? I'm a little jealous myself.","TWN":"那我該恭喜妳成為前途光明的制裁者吧？老師也有點嫉妒妳呢。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"하지만 전 용병이 되거나 싸우는 건 별로 관심이 없는 걸요!","JPN":"でも私は傭兵になったり、\\n戦うのはあまり興味がないんです！","ENG":"But I have no interest in becoming a mercenary or fighting!","TWN":"但是我當傭兵和戰鬥一點興趣都沒有啊！"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"꼭 이면세계에 가서 침식체와 싸우는 게 아니더라도, 카운터를 원하는 직장은 많아.","JPN":"裏世界に行って侵食体と戦うのでは\\nなくても、カウンターを欲しがる企業は多いからな。","ENG":"Even if you don't go to fight C.O. in the Counterside, there are a lot of jobs that require Counters.","TWN":"就算不去異界和侵蝕體作戰，想招聘制裁者的公司也很多。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"애초에 비전투 능력자들은 그런 일에 투입되지도 않고.","JPN":"そもそも、非戦闘型能力者たちは\\nそういう仕事にはつかされないだろう。","ENG":"And Counters with no combat abilities are not deployed into combat.","TWN":"而且非戰鬥能力者也不會被派到現場的。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"진로는 다양하니까 벌써부터 너무 걱정할 필요는 없어.","JPN":"進路は様々だ。今から心配する必要はないぞ。","ENG":"There are a lot of options for you. You don't have to stress about it already.","TWN":"出路有很多種，所以不用想那麼多。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"그렇군요......","JPN":"……そうですか。","ENG":"I see...","TWN":"原來如此……"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"저, 그럼 앞으로 어떻게 되는 건가요?","JPN":"そしたら、これから私はどうなるんですか？","ENG":"Then what should I do from now on?","TWN":"那我以後會怎麼樣啊？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"일단은...... 전학을 가게 될 거야.","JPN":"ひとまず……転校することになるだろう。","ENG":"First of all, you will be transferred to a new school.","TWN":"首先……妳會轉學。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"네? 전학이요?","JPN":"えっ？　転校ですか？","ENG":"What? A transfer?","TWN":"咦？轉學？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"TEACHER_EXTRA_M_NULL","text":{"KOREA":"관리국 카운터 아카데미라고 들어봤니?","JPN":"管理局カウンターアカデミーというのは聞いたことがあるか？","ENG":"Have you heard of the Administration Counter Academy?","TWN":"妳有聽過管理局制裁者學院嗎？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TEACHER_EXTRA_M_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};